// Calculate average score from Set Metrics output
const items = $input.all();
const scores = items.map(i => {
    const correctness = i.json.correctness_score || 0;
    const helpfulness = i.json.helpfulness_score || 0;
    return (correctness + helpfulness) / 2;
});
const avgScore = scores.reduce((a, b) => a + b, 0) / scores.length;
const threshold = 3.5;

return [{
    json: {
          average_score: Math.round(avgScore * 100) / 100,
          total_cases: scores.length,
          below_threshold: avgScore < threshold,
          threshold: threshold,
          scores: scores
    }
}];
